// match with range patterns and guard
match n {
    i32::MIN..=-1 => println!("negative"),
    0             => println!("zero"),
    1..=9         => println!("single digit"),
    x if x % 2 == 0 => println!("large even: {}", x),
    _             => println!("large odd"),
}

// if let — handle one variant
if let Some(v) = option_val {
    println!("{}", v);
}

