demo.code:
fn categorise(n: i32) -> &'static str {
    match n {
        i32::MIN..=-1 => "negative",
        0             => "zero",
        1..=9         => "single digit",
        _             => "large",
    }
}

fn main() {
    for n in [-3, 0, 7, 42] {
        println!("{}: {}", n, categorise(n));
    }
}

